content.text:
#!/usr/bin/env node

const API_BASE = 'https://qveris.ai/api/v1';
const API_KEY = process.env.QVERIS_API_KEY;

async function search(query, limit = 10) {
  const res = await fetch(`${API_BASE}/search`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({ query, limit })
  });
  const data = await res.json();
  return data;
}

async function execute(toolId, params, searchId = null) {
  const res = await fetch(`${API_BASE}/tools/execute`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({ tool_id: toolId, params, search_id: searchId })
  });
  const data = await res.json();
  return data;
}

async function getByIds(...ids) {
  const res = await fetch(`${API_BASE}/tools/get-by-ids`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({ ids })
  });
  const data = await res.json();
  return data;
}

