import { fetch } from 'undici';

const API_KEY = process.env.QVERIS_API_KEY;
const API_BASE = 'https://qveris.ai/api/v1';

async function execute(toolId, params) {
  const res = await fetch(`${API_BASE}/tools/execute`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({ tool_id: toolId, params })
  });
  const data = await res.json();
  return data;
}

// Try Alpha Vantage news sentiment
const result = await execute('alphavantage.news_sentiment.query.v1.7aca3c4a', {
  function: 'NEWS_SENTIMENT',
  topics: 'economy_macro,financial_markets',
  limit: 15,
  sort: 'LATEST'
