#!/usr/bin/env node

const API_BASE = 'https://qveris.ai/api/v1';
const API_KEY = process.env.QVERIS_API_KEY;

async function search(query, limit = 10) {
  const res = await fetch(`${API_BASE}/search`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({ query, limit })
  });
  const data = await res.json();
  return data;
}

async function execute(toolId, params, searchId = null) {
  const res = await fetch(`${API_BASE}/tools/execute`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({ tool_id: toolId, params, search_id: searchId })
  });
  const data = await res.json();
  return data;
}

async function getByIds(...ids) {
  const res = await fetch(`${API_BASE}/tools/get-by-ids`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({ ids })
  });
  const data = await res.json();
  return data;
}

const cmd = process.argv[2];
const args = process.argv.slice(3);

async function main() {
  try {
    if (cmd === 'search') {
      const query = args[0];
      const limit = args.includes('--limit') ? parseInt(args[args.indexOf('--limit') + 1]) : 10;
      const result = await search(query, limit);
      console.log(JSON.stringify(result, null, 2));
    } else if (cmd === 'execute') {
      const toolId = args[0];
      const searchIdIdx = args.indexOf('--search-id');
      const searchId = searchIdIdx > -1 ? args[searchIdIdx + 1] : null;
      const paramsIdx = args.indexOf('--params');
      const params = paramsIdx > -1 ? JSON.parse(args[paramsIdx + 1]) : {};
      const result = await execute(toolId, params, searchId);
      console.log(JSON.stringify(result, null, 2));
    } else if (cmd === 'get-by-ids') {
      const result = await getByIds(...args.filter(a => !a.startsWith('--')));
      console.log(JSON.stringify(result, null, 2));
    } else {
      console.error('Unknown command:', cmd);
      process.exit(1);
    }
  } catch (err) {
    console.error('Error:', err.message);
    process.exit(1);
  }
}

main();

